import React, { Component } from 'react';
import defaultImg from "./image/default.jpg";

class Application extends Component {
    constructor (props) {
        super(props);

        const saveProfile = JSON.parse(localStorage.getItem("userProfile")) || {};
        const saveImg =  localStorage.getItem("profileImg");

        this.state = {
            firstName : saveProfile.firstName || "",
            lastName : saveProfile.lastName || "",
            mobile : saveProfile.mobile || "",
            password : saveProfile.password || "",
            email : saveProfile.email || "",
            regDate : saveProfile.regDate || "",
            add1 : saveProfile.add1 || "",
            add2 : saveProfile.add2 || "",
            province : saveProfile.province || "",
            district : saveProfile.district || "",
            profileImg : saveImg || saveProfile.profileImg || defaultImg || "",
            showPass : false
        };
        this.fileInputRef = React.createRef();
    }

    handleChange = (event) => {
        const name = event.target.name;
        const value = event.target.value;
        this.setState( {...this.state, [name] : value} );
    };

    toggolePass = () => {
        this.setState ( {showPass : !this.state.showPass} );
    };

    handleProfileChange = (event) => {
        const file = event.target.files[0];

        if (file) {
            const reader = new FileReader();

            reader.onload = (event) => {
                localStorage.setItem ("profileImg", event.target.result);
                this.setState( {profileImg : event.target.result} );
            };
            reader.readAsDataURL(file);
        }
    };

    handleSubmit = (event) => {
        event.preventDefault();

        const requiredFile = [
            "firstName", "lastName", "mobile", "password", "email", "regDate", "add1", "add2", "province", "district"
        ];

        for (let feild of requiredFile) {
            if (!this.state[feild]) {
                alert ("⚠️ Please fill all requirred fields!");
                return;
            }
        }
        localStorage.setItem("userProfile", JSON.stringify(this.state));
        alert ("✅ Prifile upated successfully!");
    }

    render() { 
        return (
            <div
                style={{
                    display: "flex",
                    justifyContent: "center",
                    alignItems: "flex-start",
                    minHeight: "100vh",
                    background: "#f7f7f7"
                }}
            >
            {/* Left Side */}

            <div
                style={{
                    width: 320,
                    background: "#fff",
                    borderRadius: 12,
                    boxShadow: "0 2px 8px #eee",
                    padding: 32,
                    marginRight: 32,
                    textAlign: "center"
                }}
            >
                <img 
                    src = {this.state.profileImg}
                    alt = 'Profile'
                    style={{
                        width: 120,
                        height: 120,
                        borderRadius: "50%",
                        objectFit: "cover",
                        marginBottom: 16,
                    }}
                />
                <h4 style={ {margin : "8px 0 4px"} }> 
                    {(this.state.firstName || "") + " " + (this.state.lastName || "") || "YouR Name"}
                </h4>

                <div style={ { color: "#888", fontSize: 15, marginBottom: 24 } }>
                    {this.state.email || "Your@email.com"}
                </div>

                <input 
                    type = 'file'
                    accept = 'image/*'
                    style = { {display : "none"} }
                    ref = {this.fileInputRef}
                    onChange = {this.handleProfileChange}
                />
                <button
                    className = 'btn btn-primary'
                    onClick = { () => this.fileInputRef.current.click()}
                >
                Update Image

                </button>
            </div>

            {/* Right Side */}

            <div 
                style={{
                    flex: 1,
                    background: "#fff",
                    borderRadius: 12,
                    boxShadow: "0 2px 8px #eee",
                    padding: 32,
                    maxWidth: 600,
                }}
            >
                <h3 style = { {marginBottom : 24} }> Profile Settings </h3>

                <form onSubmit = {this.handleSubmit}>
                    <div className = 'row mb-3'>
                        <div className = 'col'>
                            <label> First Name </label>

                            <input 
                                type = 'text'
                                className = 'form-control'
                                name = 'firstName'
                                onChange = {this.handleChange}
                            />
                        </div>

                        <div className = 'col'>
                            <label> Last Name </label>

                            <input 
                                type = 'text'
                                className = 'form-control'
                                name = 'lastName'
                                onChange = {this.handleChange}
                            />
                        </div>

                        <div className = 'mb-3'>
                            <label> Mobile </label>

                            <input 
                                type = 'text'
                                className = 'form-control'
                                name = 'mobile'
                                value = {this.state.mobile}
                                onChange = {this.handleChange}
                            />
                        </div>

                        <div className = 'mb-3' style = {{position : 'relative'}}>
                            <label> Password </label>

                            <input 
                                type = 'text'
                                className = 'form-control'
                                name = 'password'
                                value = {this.state.password}
                                onChange = {this.handleChange}
                            />
                        </div>

                        <button
                            type = 'button'
                            className = 'btn btn-outtttliine-secondary'
                            style={{
                                position: "absolute",
                                right: 8,
                                top: 32,
                                padding: "2px 8px",
                            }}
                            onClick = {this.toggolePass}
                        >
                            {this.state.showPass ? "Hide" : "Show"}                            
                        </button>
                    </div>


                </form>

            </div>

            </div>
        );
    }
}

export default Application;
